import React, { useEffect, useState } from "react";
import { Table, Button, Input, Modal, Form, Switch, Badge as AntBadge } from "antd";
import { Trash2, Plus, Pencil, Search, Image as ImageIcon, ExternalLink, Megaphone, Zap, Layout } from "lucide-react";
import axios from "axios";
import { toast } from "react-toastify";
import { base_url } from "../../utils/baseUrl";
import { config } from "../../utils/axiosconfig";
import Dropzone from "react-dropzone";

const { TextArea } = Input;

const PopupAds = () => {
  const [ads, setAds] = useState([]);
  const [loading, setLoading] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [form] = Form.useForm();
  const [searchText, setSearchText] = useState("");
  const [adImage, setAdImage] = useState(null);
  const [uploading, setUploading] = useState(false);

  useEffect(() => {
    fetchAds();
  }, []);

  const fetchAds = async () => {
    setLoading(true);
    try {
      // Fetch blogs filtered by category 'Popup'
      const res = await axios.get(`${base_url}blog`, config);
      const popups = res.data.filter(b => b.category === "Popup");
      setAds(popups);
    } catch (error) {
      toast.error("Failed to fetch popup ads");
    }
    setLoading(false);
  };

  const showModal = (record = null) => {
    setIsModalOpen(true);
    if (record) {
      setEditingId(record._id);
      setAdImage(record.images?.[0] || null);
      form.setFieldsValue({
        title: record.title,
        description: record.description,
        link: record.link || "", 
      });
    } else {
      setEditingId(null);
      setAdImage(null);
      form.resetFields();
    }
  };

  const handleCancel = () => {
    setIsModalOpen(false);
    form.resetFields();
    setEditingId(null);
    setAdImage(null);
  };

  const handleImageUpload = async (files) => {
    setUploading(true);
    try {
      const formData = new FormData();
      formData.append("multiple_image", files[0]);
      const res = await axios.post(`${base_url}upload/create`, formData, {
        headers: {
          ...config.headers,
          "Content-Type": "multipart/form-data",
        },
      });
      if (res.data?.[0]) {
        setAdImage({
          public_id: res.data[0].public_id,
          secure_url: res.data[0].secure_url,
        });
        toast.success("Ad image uploaded");
      }
    } catch (error) {
      toast.error("Upload failed");
    }
    setUploading(false);
  };

  const onFinish = async (values) => {
    const payload = {
      ...values,
      category: "Popup",
      images: adImage ? [adImage] : [],
    };

    try {
      if (editingId) {
        await axios.put(`${base_url}blog/${editingId}`, payload, config);
        toast.success("Popup Updated");
      } else {
        await axios.post(`${base_url}blog`, payload, config);
        toast.success("Popup Created");
      }
      setIsModalOpen(false);
      fetchAds();
    } catch (error) {
      toast.error("Operation failed");
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm("Terminate this broadcast?")) {
      try {
        await axios.delete(`${base_url}blog/${id}`, config);
        toast.success("Broadcast terminated");
        fetchAds();
      } catch (error) {
        toast.error("Delete failed");
      }
    }
  };

  const columns = [
    {
      title: "Preview",
      dataIndex: "images",
      width: 100,
      render: (imgs) => {
        const url = Array.isArray(imgs) ? imgs?.[0]?.secure_url : imgs?.secure_url;
        return url ? (
          <div className="w-20 h-14 rounded-xl overflow-hidden border border-slate-100 shadow-sm bg-slate-50">
            <img src={url} alt="ad" className="w-full h-full object-cover" />
          </div>
        ) : (
          <div className="w-20 h-14 bg-slate-50 flex items-center justify-center rounded-xl border border-slate-100 text-slate-300">
            <ImageIcon size={18} />
          </div>
        );
      },
    },
    {
      title: "Campaign Title",
      dataIndex: "title",
      render: (text) => (
        <span className="font-bold text-slate-900 text-[15px] leading-tight">{text}</span>
      ),
    },
    {
      title: "Content",
      dataIndex: "description",
      render: (text) => (
        <div
          className="text-slate-500 text-[13px] line-clamp-2 leading-relaxed max-w-xs"
          dangerouslySetInnerHTML={{ __html: text }}
        />
      ),
    },
    {
      title: "Status",
      key: "status",
      width: 120,
      render: () => (
        <div className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-emerald-50 border border-emerald-100 w-fit">
          <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
          <span className="text-[11px] font-semibold text-emerald-700">Live</span>
        </div>
      ),
    },
    {
      title: "Actions",
      key: "actions",
      width: 90,
      render: (_, record) => (
        <div className="flex items-center gap-2">
          <Button
            type="text"
            icon={<Pencil size={16} />}
            onClick={() => showModal(record)}
            className="w-9 h-9 flex items-center justify-center rounded-lg text-slate-400 hover:text-blue-600 hover:bg-blue-50 border border-slate-100 hover:border-blue-200 transition-all"
          />
          <Button
            type="text"
            icon={<Trash2 size={16} />}
            onClick={() => handleDelete(record._id)}
            className="w-9 h-9 flex items-center justify-center rounded-lg text-slate-400 hover:text-rose-600 hover:bg-rose-50 border border-slate-100 hover:border-rose-200 transition-all"
          />
        </div>
      ),
    },
  ];

  const filteredData = ads.filter(
    (a) =>
      !searchText ||
      a.title?.toLowerCase().includes(searchText.toLowerCase())
  );

  return (
    <div className="space-y-12 pb-20 animate-in fade-in duration-700">
      {/* Premium Header */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8">
        <div className="space-y-2">
          <div className="flex items-center gap-3 mb-2">
            <div className="w-1.5 h-1.5 rounded-full bg-blue-600 animate-pulse" />
            <span className="text-[11px] font-black text-blue-600 uppercase tracking-[0.3em]">Broadcast Command</span>
          </div>
          <h1 className="text-[42px] font-black text-slate-900 tracking-tighter leading-none">
            Popup Ads <span className="text-blue-600">Assistant</span>
          </h1>
          <p className="text-[16px] text-slate-400 font-bold max-w-xl">
            Deploy high-fidelity marketing popups across the customer interface.
          </p>
        </div>
        
        <div className="flex items-center gap-4 w-full lg:w-auto">
           <div className="relative flex-1 lg:w-80">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
              <input
                type="text"
                placeholder="Search campaigns..."
                className="w-full h-14 pl-12 pr-6 bg-white border border-slate-100 rounded-[20px] focus:outline-none focus:ring-4 focus:ring-blue-500/5 transition-all text-[15px] font-bold shadow-sm"
                onChange={(e) => setSearchText(e.target.value)}
              />
           </div>
           <Button
              type="primary"
              onClick={() => showModal()}
              className="h-14 bg-slate-950 text-white font-black text-[13px] uppercase tracking-widest px-8 rounded-[20px] border-none flex items-center gap-3 hover:bg-blue-600 shadow-xl shadow-slate-900/10 transition-all"
            >
              <Plus size={20} strokeWidth={3} /> Issue Ad
            </Button>
        </div>
      </div>

      {/* Modern Grid Table */}
      <div className="bg-white rounded-[40px] border border-slate-100 overflow-hidden shadow-2xl shadow-slate-200/40">
        <div className="p-10 border-b border-slate-50 flex items-center justify-between bg-slate-50/30">
           <div className="flex items-center gap-4">
              <div className="w-12 h-12 rounded-2xl bg-blue-600 text-white flex items-center justify-center shadow-lg shadow-blue-500/20">
                 <Megaphone size={24} />
              </div>
              <div>
                 <h3 className="text-[18px] font-black text-slate-900 leading-none uppercase tracking-tight">Active Broadcasts</h3>
                 <p className="text-[13px] text-slate-400 font-bold mt-1 uppercase tracking-widest">{filteredData.length} Campaigns Ready</p>
              </div>
           </div>
           <div className="flex items-center gap-3 bg-white p-2 rounded-2xl border border-slate-100 shadow-sm">
              <span className="text-[11px] font-black text-slate-400 uppercase tracking-widest ml-2">Network Health</span>
              <div className="w-3 h-3 rounded-full bg-emerald-500 animate-ping" />
           </div>
        </div>

        <Table
          columns={columns}
          dataSource={filteredData}
          rowKey="_id"
          loading={loading}
          pagination={{ pageSize: 10, className: "px-6 py-4" }}
          className="modern-table"
        />
      </div>

      {/* Global Intelligence Card */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
         <div className="glass-panel p-8 rounded-[36px] bg-slate-900 border border-white/5 text-white relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:scale-110 transition-transform">
               <Zap size={140} />
            </div>
            <h4 className="text-[14px] font-black text-blue-400 uppercase tracking-[0.2em] mb-6">Performance Matrix</h4>
            <div className="space-y-2">
               <p className="text-[32px] font-black tracking-tighter">84.2%</p>
               <p className="text-[13px] text-slate-400 font-bold uppercase tracking-widest">Average Conversion Increase</p>
            </div>
         </div>
         <div className="glass-panel p-8 rounded-[36px] bg-white border border-slate-100 relative overflow-hidden group shadow-lg">
             <h4 className="text-[14px] font-black text-slate-400 uppercase tracking-[0.2em] mb-6">Optimization Tip</h4>
             <p className="text-[15px] text-slate-700 font-bold leading-relaxed">
               Popups with <span className="text-blue-600 underline">Promo Codes</span> outperform generic landing ads by significant margins. Ensure codes are active in your Coupon Registry.
             </p>
         </div>
         <div className="glass-panel p-8 rounded-[36px] bg-blue-600 text-white relative overflow-hidden group shadow-2xl shadow-blue-500/20">
             <h4 className="text-[14px] font-black text-white/60 uppercase tracking-[0.2em] mb-6">System Alert</h4>
             <p className="text-[15px] font-black leading-relaxed">
               All broadcasts are encrypted and optimized for mobile devices automatically. No further scaling required.
             </p>
         </div>
      </div>

      <Modal
        title={null}
        open={isModalOpen}
        onCancel={handleCancel}
        footer={null}
        width={680}
        className="modern-super-modal"
        centered
      >
        <div className="p-8">
           <div className="flex items-center gap-4 mb-10">
              <div className="w-14 h-14 rounded-2xl bg-slate-900 text-white flex items-center justify-center">
                 <Layout size={28} />
              </div>
              <div>
                 <h2 className="text-[24px] font-black text-slate-900 leading-none uppercase tracking-tighter">
                   {editingId ? "Refine Broadcast" : "Issue New Ad"}
                 </h2>
                 <p className="text-[13px] text-slate-400 font-bold mt-2 uppercase tracking-widest">Configure marketing protocol</p>
              </div>
           </div>

           <Form form={form} layout="vertical" onFinish={onFinish} className="space-y-6">
              <Form.Item
                name="title"
                label={<span className="text-[12px] font-black uppercase text-slate-400 tracking-widest">Campaign Headline</span>}
                rules={[{ required: true, message: "Identification Required" }]}
              >
                <Input placeholder="e.g. Flash 72-Hour Medical Sale" className="modern-input-field" />
              </Form.Item>

              <div className="space-y-2">
                 <label className="text-[12px] font-black uppercase text-slate-400 tracking-widest block mb-1">Visual Asset</label>
                 <div className="h-48 relative">
                    {adImage ? (
                      <div className="h-full w-full rounded-2xl overflow-hidden border border-slate-100 relative group bg-slate-50">
                         <img src={adImage.secure_url} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" alt="Preview" />
                         <div className="absolute inset-0 bg-slate-900/20 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                            <button 
                              type="button"
                              onClick={() => setAdImage(null)}
                              className="w-12 h-12 bg-white text-rose-600 rounded-2xl flex items-center justify-center shadow-2xl hover:bg-rose-50 transition-all font-black"
                            >
                              <Trash2 size={24} />
                            </button>
                         </div>
                      </div>
                    ) : (
                      <Dropzone onDrop={handleImageUpload} multiple={false}>
                        {({getRootProps, getInputProps}) => (
                          <div {...getRootProps()} className="border-2 border-dashed border-slate-100 rounded-2xl h-full flex flex-col items-center justify-center cursor-pointer hover:border-blue-400 hover:bg-blue-50/20 transition-all bg-slate-50/50 group">
                            <input {...getInputProps()} />
                            <ImageIcon size={32} className="text-slate-300 mb-3 group-hover:translate-y-[-5px] transition-transform" />
                            <span className="text-[13px] text-slate-400 font-bold uppercase tracking-widest">Deploy High-Res Asset</span>
                          </div>
                        )}
                      </Dropzone>
                    )}
                 </div>
              </div>

              <Form.Item
                name="description"
                label={<span className="text-[12px] font-black uppercase text-slate-400 tracking-widest">Ad Copy (HTML Supported)</span>}
                rules={[{ required: true, message: "Payload Required" }]}
              >
                <TextArea rows={4} placeholder="<strong>Exclusive 20% Discount</strong> on all diagnostic tools..." className="modern-input-field" style={{padding: '16px'}} />
              </Form.Item>

              <div className="flex gap-4 pt-6">
                 <Button onClick={handleCancel} className="flex-1 h-16 rounded-2xl font-black uppercase text-[12px] tracking-widest border-slate-100 text-slate-400 hover:text-slate-900 transition-all">
                   Abort
                 </Button>
                 <Button type="primary" htmlType="submit" loading={uploading} className="flex-1 h-16 rounded-2xl font-black uppercase text-[12px] tracking-widest bg-blue-600 border-none hover:bg-blue-700 transition-all shadow-xl shadow-blue-500/20">
                   {editingId ? "Update Cluster" : "Initiate Protocol"}
                 </Button>
              </div>
           </Form>
        </div>
      </Modal>

      <style>{`
        .super-modern-table .ant-table-thead > tr > th {
          background: #fbfcfd !important;
          font-weight: 800 !important;
          font-size: 11px !important;
          color: #94a3b8 !important;
          text-transform: uppercase !important;
          letter-spacing: 0.15em !important;
          border-bottom: 2px solid #f1f5f9 !important;
          padding: 24px 40px !important;
        }
        .super-modern-table .ant-table-tbody > tr > td {
          padding: 24px 40px !important;
          border-bottom: 1px solid #f8fafc !important;
          color: #1e293b !important;
        }
        .super-modern-table .ant-table-row:hover {
          background: #fbfcfe !important;
        }
        
        .modern-input-field {
          background: #f8fafc !important;
          border: 1px solid #f1f5f9 !important;
          border-radius: 16px !important;
          padding: 0 20px !important;
          height: 56px !important;
          font-size: 15px !important;
          font-weight: 700 !important;
          transition: all 0.3s !important;
          box-shadow: inset 0 2px 4px 0 rgba(0, 0, 0, 0.02) !important;
        }
        .modern-input-field:focus {
          border-color: #3b82f6 !important;
          background: #fff !important;
          box-shadow: 0 10px 15px -3px rgba(59, 130, 246, 0.1) !important;
        }
        
        .modern-super-modal .ant-modal-content {
          border-radius: 48px !important;
          padding: 0 !important;
          overflow: hidden !important;
          border: 1px solid #f1f5f9 !important;
          box-shadow: 0 40px 100px -20px rgba(0,0,0,0.2) !important;
        }
      `}</style>
    </div>
  );
};

export default PopupAds;
